import React, { useState, useEffect, useRef } from 'react';
import { PiDotsThreeBold } from "react-icons/pi";
import { PiStopThin } from "react-icons/pi";
import { PiTrashThin } from "react-icons/pi";
import { PiPlayThin } from "react-icons/pi";
import { HiOutlinePause } from "react-icons/hi2";
import WinModalQuest from '../../../UI/WinModalQuest/WinModalQuest';
import './timer.css';

const Timer = ({ targetDateTime, files = [], slideInterval = 4, timerName = '', timerData = null, onDelete }) => {
    const [timeLeft, setTimeLeft] = useState(0);
    const [isActive, setIsActive] = useState(false);
    const [isTimerPaused, setIsTimerPaused] = useState(false);
    const [currentFileIndex, setCurrentFileIndex] = useState(0);
    const [isAtTop, setIsAtTop] = useState(false);
    const [elementsHidden, setElementsHidden] = useState(false);
    const [userHiddenElements, setUserHiddenElements] = useState(false);
    const [stopwatchTime, setStopwatchTime] = useState(0);
    const [isStopwatchActive, setIsStopwatchActive] = useState(false);
    const [isStopwatchPaused, setIsStopwatchPaused] = useState(false);
    const [showMenu, setShowMenu] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);

    const intervalRef = useRef(null);
    const slideIntervalRef = useRef(null);
    const stopwatchRef = useRef(null);
    const timerRef = useRef(null);
    const menuRef = useRef(null);

    // Основной эффект для таймера обратного отсчета
    useEffect(() => {
        if (!targetDateTime) {
            setIsActive(false);
            setTimeLeft(0);
            return;
        }

        const targetTime = new Date(targetDateTime).getTime();

        const updateTimeLeft = () => {
            const now = new Date().getTime();
            const diff = Math.floor((targetTime - now) / 1000);

            if (diff >= 0) {
                setTimeLeft(diff);
                setIsActive(true);
            } else {
                setTimeLeft(0);
                setIsActive(false);
                clearInterval(intervalRef.current);
                intervalRef.current = null;

                // Таймер закончился - удаляем блок через 2 секунды
                const timer = setTimeout(() => {
                    if (onDelete) {
                        onDelete();
                    }
                }, 1000);

                return () => clearTimeout(timer);
            }
        };

        updateTimeLeft();

        if (intervalRef.current) {
            clearInterval(intervalRef.current);
        }

        intervalRef.current = setInterval(updateTimeLeft, 1000);

        return () => {
            if (intervalRef.current) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
        };
    }, [targetDateTime, onDelete]);

    // Эффект для автоматической смены картинок
    useEffect(() => {
        if (files.length > 1 && isActive && !isTimerPaused) {
            slideIntervalRef.current = setInterval(() => {
                setCurrentFileIndex(prev => (prev + 1) % files.length);
            }, slideInterval * 1000);
        } else {
            if (slideIntervalRef.current) {
                clearInterval(slideIntervalRef.current);
                slideIntervalRef.current = null;
            }
        }

        return () => {
            if (slideIntervalRef.current) {
                clearInterval(slideIntervalRef.current);
                slideIntervalRef.current = null;
            }
        };
    }, [files.length, isActive, isTimerPaused, slideInterval]);

    // Эффект для отслеживания позиции таймера
    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting && entry.boundingClientRect.top <= 0) {
                        setIsAtTop(true);
                        if (!userHiddenElements) {
                            setElementsHidden(true);
                        }
                    } else {
                        setIsAtTop(false);
                    }
                });
            },
            {
                threshold: 0,
                rootMargin: '0px 0px -100% 0px'
            }
        );

        const currentTimerRef = timerRef.current;
        if (currentTimerRef) {
            observer.observe(currentTimerRef);
        }

        return () => {
            if (currentTimerRef) {
                observer.unobserve(currentTimerRef);
            }
        };
    }, [userHiddenElements]);

    // Эффект для работы секундомера
    useEffect(() => {
        if (timerData && timerData.type === 'stopwatch' && timerData.isActive) {
            setIsStopwatchActive(true);
            setStopwatchTime(timerData.initialTime || 0);

            if (stopwatchRef.current) {
                clearInterval(stopwatchRef.current);
            }

            stopwatchRef.current = setInterval(() => {
                setStopwatchTime(prev => prev + 1);
            }, 1000);

            return () => {
                if (stopwatchRef.current) {
                    clearInterval(stopwatchRef.current);
                    stopwatchRef.current = null;
                }
            };
        } else {
            setIsStopwatchActive(false);
            setIsStopwatchPaused(false);
            if (stopwatchRef.current) {
                clearInterval(stopwatchRef.current);
                stopwatchRef.current = null;
            }
        }
    }, [timerData]);

    // Обработчик клика вне меню
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (menuRef.current && !menuRef.current.contains(event.target)) {
                setShowMenu(false);
            }
        };

        if (showMenu) {
            document.addEventListener('mousedown', handleClickOutside);
            return () => document.removeEventListener('mousedown', handleClickOutside);
        }
    }, [showMenu]);

    const formatTime = (seconds) => {
        const d = Math.floor(seconds / (3600 * 24));
        const h = Math.floor((seconds % (3600 * 24)) / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;

        let formatted = '';
        if (d > 0) formatted += d + 'd ';
        formatted += `${h.toString().padStart(2, '0')}:`;
        formatted += `${m.toString().padStart(2, '0')}:`;
        formatted += `${s.toString().padStart(2, '0')}`;
        return formatted;
    };

    const toggleElementsVisibility = () => {
        setElementsHidden(prev => {
            if (prev) {
                setUserHiddenElements(false);
                return false;
            } else {
                setUserHiddenElements(prevUser => !prevUser);
                return prev;
            }
        });
    };

    const toggleMenu = (e) => {
        e.stopPropagation();
        setShowMenu(prev => !prev);
    };

    // Функции управления таймером
    const handleStartTimer = () => {
        if (!targetDateTime) return;

        const targetTime = new Date(targetDateTime).getTime();
        const now = new Date().getTime();
        const diff = Math.floor((targetTime - now) / 1000);

        if (diff > 0) {
            setTimeLeft(diff);
            setIsActive(true);
            setIsTimerPaused(false);

            if (intervalRef.current) {
                clearInterval(intervalRef.current);
            }

            intervalRef.current = setInterval(() => {
                const currentNow = new Date().getTime();
                const currentDiff = Math.floor((targetTime - currentNow) / 1000);
                if (currentDiff >= 0) {
                    setTimeLeft(currentDiff);
                } else {
                    setTimeLeft(0);
                    setIsActive(false);
                    clearInterval(intervalRef.current);
                    intervalRef.current = null;
                }
            }, 1000);
        }
        setShowMenu(false);
    };

    const handlePauseTimer = () => {
        setIsTimerPaused(true);
        clearInterval(intervalRef.current);
        intervalRef.current = null;
        setShowMenu(false);
    };

    const handleResumeTimer = () => {
        if (!targetDateTime) return;

        setIsTimerPaused(false);
        const targetTime = new Date(targetDateTime).getTime();
        const now = new Date().getTime();
        const diff = Math.floor((targetTime - now) / 1000);

        if (diff > 0) {
            setTimeLeft(diff);
            setIsActive(true);

            intervalRef.current = setInterval(() => {
                const currentNow = new Date().getTime();
                const currentDiff = Math.floor((targetTime - currentNow) / 1000);
                if (currentDiff >= 0) {
                    setTimeLeft(currentDiff);
                } else {
                    setTimeLeft(0);
                    setIsActive(false);
                    clearInterval(intervalRef.current);
                    intervalRef.current = null;
                }
            }, 1000);
        }
        setShowMenu(false);
    };

    const handleStopTimer = () => {
        setIsActive(false);
        setIsTimerPaused(false);
        setTimeLeft(0);
        clearInterval(intervalRef.current);
        intervalRef.current = null;
        setShowMenu(false);
    };

    // Функции управления секундомером
    const handlePauseStopwatch = () => {
        setIsStopwatchPaused(true);
        clearInterval(stopwatchRef.current);
        stopwatchRef.current = null;
        setShowMenu(false);
    };

    const handleResumeStopwatch = () => {
        setIsStopwatchPaused(false);
        setIsStopwatchActive(true);

        stopwatchRef.current = setInterval(() => {
            setStopwatchTime(prev => prev + 1);
        }, 1000);
        setShowMenu(false);
    };

    const handleStartStopwatch = () => {
        setIsStopwatchActive(true);
        setIsStopwatchPaused(false);
        setStopwatchTime(0);

        clearInterval(stopwatchRef.current);

        stopwatchRef.current = setInterval(() => {
            setStopwatchTime(prev => prev + 1);
        }, 1000);
        setShowMenu(false);
    };

    const handleStopStopwatch = () => {
        setIsStopwatchActive(false);
        setIsStopwatchPaused(false);
        setStopwatchTime(0);
        clearInterval(stopwatchRef.current);
        stopwatchRef.current = null;
        setShowMenu(false);
    };

    const handleDeleteTimer = () => {
        setShowDeleteModal(true);
        setShowMenu(false);
    };

    const handleConfirmDelete = () => {
        // Очищаем все интервалы перед удалением
        clearInterval(intervalRef.current);
        clearInterval(slideIntervalRef.current);
        clearInterval(stopwatchRef.current);

        if (onDelete) {
            onDelete();
        }
        setShowDeleteModal(false);
    };

    const handleCloseDeleteModal = () => {
        setShowDeleteModal(false);
    };

    const currentFile = files[currentFileIndex];
    const displayTime = isStopwatchActive ? stopwatchTime : timeLeft;
    const displayName = isStopwatchActive ? (timerData?.name || timerName) : timerName;
    const shouldShowElements = !elementsHidden && !userHiddenElements;

    return (
        <div className='timer_block' ref={timerRef}>
            <div style={{ position: 'relative' }}>
                {showMenu && (
                    <div className='timer_menu' ref={menuRef}>
                        {timerData?.type === 'stopwatch' ? (
                            // Меню для секундомера
                            isStopwatchActive && !isStopwatchPaused ? (
                                <>
                                    <PiStopThin className='menu_icon' onClick={handleStopStopwatch} />
                                    <HiOutlinePause onClick={handlePauseStopwatch} className='menu_icon' />
                                    <PiTrashThin onClick={handleDeleteTimer} className='menu_icon' />
                                </>
                            ) : isStopwatchActive && isStopwatchPaused ? (
                                <>
                                    <PiStopThin className='menu_icon' onClick={handleStopStopwatch} />
                                    <PiPlayThin className='menu_icon' onClick={handleResumeStopwatch} />
                                    <PiTrashThin className='menu_icon' onClick={handleDeleteTimer} />
                                </>
                            ) : (
                                <>
                                    <PiPlayThin className='menu_icon' onClick={handleStartStopwatch} />
                                    <PiTrashThin className='menu_icon' onClick={handleDeleteTimer} />
                                </>
                            )
                        ) : (
                            // Меню для обычного таймера
                            isActive && !isTimerPaused ? (
                                <>
                                    <PiStopThin className='menu_icon' onClick={handleStopTimer} />
                                    <HiOutlinePause className='menu_icon' onClick={handlePauseTimer} />
                                    <PiTrashThin className='menu_icon' onClick={handleDeleteTimer} />
                                </>
                            ) : isActive && isTimerPaused ? (
                                <>
                                    <PiStopThin className='menu_icon' onClick={handleStopTimer} />
                                    <PiPlayThin className='menu_icon' onClick={handleResumeTimer} />
                                    <PiTrashThin className='menu_icon' onClick={handleDeleteTimer} />
                                </>
                            ) : (
                                <>
                                    <PiPlayThin className='menu_icon' onClick={handleStartTimer} />
                                    <PiTrashThin className='menu_icon' onClick={handleDeleteTimer} />
                                </>
                            )
                        )}
                    </div>
                )}
            </div>

            <div className='timer_display' onClick={toggleElementsVisibility} style={{ cursor: 'pointer' }}>
                <div className='timer_text'>
                    {formatTime(displayTime)}
                    <PiDotsThreeBold className='delete_timer' onClick={toggleMenu} />
                </div>

                {files.length > 0 && currentFile && shouldShowElements && (
                    <div className={`timer_file_item ${isAtTop ? 'hidden' : ''}`}>
                        {currentFile.type.startsWith('image/') ? (
                            <img
                                src={currentFile.url}
                                alt={currentFile.name}
                                className="timer_file_preview"
                                style={{ scale: currentFile.scale || 1 }}
                                onClick={() => console.log(currentFile.name)}
                            />
                        ) : currentFile.type.startsWith('video/') ? (
                            <video
                                src={currentFile.url}
                                className="timer_file_preview"
                                style={{ scale: currentFile.scale || 1 }}
                                controls
                            />
                        ) : null}
                    </div>
                )}
            </div>

            {displayName && shouldShowElements && (
                <div className={`timer_name ${isAtTop ? 'hidden' : ''}`}>
                    {displayName}
                </div>
            )}

            {showDeleteModal && (
                <WinModalQuest
                    onClose={handleCloseDeleteModal}
                    onConfirm={handleConfirmDelete}
                >
                    {timerData?.type === 'stopwatch' ? 'Удалить секундомер?' : 'Удалить таймер?'}
                </WinModalQuest>
            )}
        </div>
    );
};

export default Timer;